```class Solution {
public:
    int kthFactor(int n, int k) {
        int factors[] = {1};
        int i = 1;
        while (factors.size() < k) {
            for (int j = 1; j <= n; j++) {
                if (n % i == 0) {
                    factors.push_back(i);
                }
            }
            i++;
        }
        return factors[k - 1];
    }
};
```

